class Solution:
    def minimumRightShifts(self, nums):
        n = len(nums)
        for shifts in range(n):
            shifted = nums[-shifts:] + nums[:-shifts] if shifts else nums[:]
            if shifted == sorted(shifted):
                return shifts
        return -1

