class Solution:
    def minimumRightShifts(self, nums) -> int:
        n = len(nums)
        if n == 1:
            return 0
        drops = []
        for i in range(n):
            if nums[i] > nums[(i + 1) % n]:
                drops.append(i)
        if len(drops) == 0:
            return 0
        if len(drops) > 1:
            return -1
        p = drops[0]
        return (n - p - 1) % n

