var minimumRightShifts = function(nums) {
    const n = nums.length;
    if (n === 1) return 0;
    let count = 0, p = -1;
    for (let i = 0; i < n; i++) {
        if (nums[i] > nums[(i + 1) % n]) {
            count++;
            p = i;
        }
    }
    if (count === 0) return 0;
    if (count > 1) return -1;
    return (n - p - 1) % n;
};
